// ─── Scoring + WHS handicap engine ───────────────────────────────────────────
// Strokes received on a hole, given playing handicap and stroke index
function strokesReceived(hcp, si) {
  const h = Math.round(hcp);
  return Math.floor(h / 18) + (si <= (h % 18) ? 1 : 0);
}
// Stableford points for a hole from gross strokes
function stablefordPts(gross, par, hcp, si) {
  if (!gross) return null;
  const net = gross - (par + strokesReceived(hcp, si));
  if (net <= -2) return 4 + Math.abs(net) - 2; // albatross+ scales up
  if (net === -1) return 3;
  if (net === 0) return 2;
  if (net === 1) return 1;
  return 0;
}
// WHS Score Differential for a single round
function scoreDifferential(adjGross, rating, slope) {
  return Math.round(((113 / slope) * (adjGross - rating)) * 10) / 10;
}
// Net new handicap index from a list of differentials (most recent last), per WHS table
function calcHandicapIndex(diffs) {
  const n = diffs.length;
  if (n === 0) return null;
  const recent = diffs.slice(-20);
  const table = [
    [1,1],[2,1],[3,1],[4,2],[5,2],[6,2],[7,3],[8,3],[9,4],[10,4],
    [11,5],[12,5],[13,6],[14,6],[15,7],[16,7],[17,8],[18,8],[19,9],[20,8],
  ];
  const count = recent.length;
  const useCount = (table.find(([c]) => c === count) || table[table.length - 1])[1];
  const sorted = [...recent].sort((a, b) => a - b);
  const best = sorted.slice(0, useCount);
  const avg = best.reduce((s, d) => s + d, 0) / best.length;
  return Math.round(avg * 0.96 * 10) / 10;
}

// Decides whether the system should take over calculating someone's handicap
// from their round history, or leave their manually-entered starting figure
// alone. Rule: if they typed in a starting handicap and the system has never
// calculated one for them before, wait until they've logged at least 3 valid
// rounds (the WHS minimum for a first real index) before taking over. Once
// the system has started (handicapHistory has at least one entry), keep
// updating every round as normal — this only protects the very first switch
// from "what I told you" to "what your scores actually show."
function shouldAutoUpdateHandicap(user, diffs) {
  const hasManualStart = user.handicap != null;
  const systemAlreadyCalculating = (user.handicapHistory || []).length > 0;
  if (!hasManualStart || systemAlreadyCalculating) return true;
  return diffs.length >= 3;
}

